insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, увидев <а>толпы, Он <1>поднялся на <б>гору. И когда Он сел, подошли к Нему Его <2>ученики. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, <а>открыв уста, Он учил их и говорил:',2,1,5,2);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Блаженны <2а>нищие <3>духом, ибо их есть <4б>царство небес.',2,1,5,3);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>скорбящие, ибо они будут <2б>утешены. ',2,1,5,4);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>кроткие, ибо они <2б>унаследуют землю.',2,1,5,5);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны алчущие и <а>жаждущие <1б>праведности, ибо они <2в>насытятся',2,1,5,6);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>милостивые, ибо им будет <2>явлена милость. ',2,1,5,7);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>чистые сердцем, ибо они <2б>увидят Бога.',2,1,5,8);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>миротворцы, ибо они будут названы <2б>сыновьями Божьими.',2,1,5,9);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>гонимые за <б>праведность, ибо <2>их есть <в>царство небес.',2,1,5,10);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны вы, когда будут <1а>поносить вас, и <б>гнать, и лживо говорить против вас всякое <в>зло <2>из-за Меня.',2,1,5,11);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<а>Радуйтесь и ликуйте, ибо велика ваша <1>бнаграда на небесах; ибо так <в>гнали <2>пророков, которые были до вас.',2,1,5,12);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Вы <2а>соль земли. Но если соль станет <3б>пресной, чем сделать её солёной? Она уже <в>ни на что не годна, разве только <4г>выбросить её, чтобы её <5>топтали люди.',2,1,5,13);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы <1а>свет мира. Невозможно, чтобы <2б>город, расположенный на горе, был скрыт.',2,1,5,14);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, зажигая <а>светильник, не ставят его под <1>сосуд, а ставят на <2б>подставку, и он сияет всем, кто в доме.',2,1,5,15);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Пусть так же <а>сияет ваш свет перед людьми, чтобы они видели ваши <1б>добрые дела и <2в>прославляли вашего <3>Отца, который на небесах.',2,1,5,16);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Не думайте, что Я пришёл упразднить <а>закон или пророков; Я пришёл не упразднить, а <2б>исполнить. ',2,1,5,17);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо истинно говорю вам: пока не уйдёт <1а>небо и земля, ни одна <2>йота и ни одна <3>чёрточка ни в коем случае не уйдёт из закона, пока всё не произойдёт.',2,1,5,18);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Итак, кто отменит одну из <а>малейших из этих <1>заповедей и так научит людей, будет назван <б>малейшим в <в>царстве небес; а кто выполнит их и научит им, тот будет назван <г>великим в царстве небес.',2,1,5,19);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо говорю вам, что если ваша <1а>праведность не превзойдёт праведности <2>книжников и фарисеев, то вы ни в коем случае не <3б>войдёте в царство небес.',2,1,5,20);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что древним было сказано: «<а>Не убивай; а кто убьёт, будет подлежать <б>суду».',2,1,5,21);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А <1>Я говорю вам, что всякий, кто <2а>гневается на своего <3>брата, будет подлежать <4б>суду. А кто скажет своему брату: «<5>Раќа», — будет подлежать суду <6в>синедриона; а кто скажет: «<7>Мор́э», — будет подлежать <8г>Геенне огненной. ',2,1,5,22);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Итак, если ты будешь приносить свой <1а>дар на <2б>жертвеннике и там вспомнишь, что твой <в>брат имеет <3>что-то против тебя,',2,1,5,23);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('То оставь там свой дар перед жертвенником и <1>прежде иди и <2а>помирись со своим братом, и тогда приходи и приноси свой дар.',2,1,5,24);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Скорее благоволи к своему <2а>противнику в суде, пока ты с ним <3>в пути, чтобы не <4>отдал тебя противник судье, а судья служителю, и ты не был брошен в тюрьму.',2,1,5,25);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Истинно говорю тебе: ни в коем случае не <1>выйдешь оттуда, пока не <а>выплатишь последнего <2>кодранта.',2,1,5,26);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что было сказано: «<а>Не прелюбодействуй».',2,1,5,27);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, что всякий, кто <а>смотрит на женщину с тем, чтобы вожделеть её, уже <б>прелюбодействовал с ней в своём <1в>сердце.',2,1,5,28);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Если же твой правый <а>глаз служит для тебя преткновением, <1>вырви его и брось от себя, ибо лучше для тебя, чтобы погиб один из твоих членов, чем чтобы всё твоё тело было брошено в <2б>Геенну.',2,1,5,29);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И если твоя правая <а>рука служит для тебя преткновением, <1>отруби её и брось от себя, ибо лучше для тебя, чтобы погиб один из твоих членов, чем чтобы всё твоё тело пошло в <б>Геенну.',2,1,5,30);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И было сказано: «<а>Кто <1>разведётся со своей женой, пусть даст ей разводное свидетельство».',2,1,5,31);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, что <1>всякий, кто <а>разводится со своей женой, кроме как по причине <2>блуда, побуждает её прелюбодействовать, и кто женится на разведённой, прелюбодействует.',2,1,5,32);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ещё вы слышали, что древним было сказано: «<1а>Не нарушай клятву, а <2б>исполняй перед Господом свои клятвы».',2,1,5,33);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, чтобы вы <а>не клялись совсем: ни <1б>небом, потому что это престол Божий;',2,1,5,34);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ни <а>землёй, потому что это подножие Его ног; ни на Иерусалим, потому что это <б>город великого Царя;',2,1,5,35);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И своей головой не клянись, потому что не можешь ни одного волоса сделать белым или чёрным.',2,1,5,36);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А пусть ваше слово будет «<1>ада, да», «нет, нет»; ибо что сверх этого, то <2>от <3>блукавого.',2,1,5,37);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что было сказано: «<а>Глаз за глаз и зуб за зуб».',2,1,5,38);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, чтобы вы <а>не противились злому человеку; напротив, кто <б>бьёт тебя по правой щеке, <1>поверни к нему и другую.',2,1,5,39);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И тому, кто хочет <а>судиться с тобой и взять твой <1>хитон, — уступи ему и плащ;',2,1,5,40);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И кто заставит тебя идти одну <1>милю — иди с ним две.',2,1,5,41);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Тому, кто просит у тебя, <1а>дай, и от того, кто хочет у тебя <б>занять, не отворачивайся.',2,1,5,42);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что было сказано: «<а>Люби твоего ближнего и ненавидь твоего <б>врага».',2,1,5,43);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам: <а>любите своих врагов и <б>молитесь за тех, кто <в>гонит вас,',2,1,5,44);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Чтобы стать вам <1а>сыновьями вашего Отца, который на небесах, потому что Он <б>возводит Своё солнце над злыми и добрыми и <2>посылает вдождь на справедливых и несправедливых.',2,1,5,45);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо если вы будете <а>любить тех, кто любит вас, какая вам <1>награда? Разве не то же самое делают и <2>сборщики налогов?',2,1,5,46);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И если будете приветствовать только своих братьев, что особенного делаете? Разве не то же самое делают и <а>язычники?',2,1,5,47);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Итак, вы будьте <1а>совершенны, <б>как совершенен ваш небесный Отец.',2,1,5,48);